(function(w){"use strict";const ID="mode";function compute(x){const raw=String(x.values||"").split(/[\s,]+/).filter(Boolean);const values=raw.map(Number);if(!values.length||values.some(v=>!Number.isFinite(v)))return{error:"숫자를 쉼표 또는 공백으로 구분해 입력해 주세요."};const counts=new Map();values.forEach(v=>counts.set(v,(counts.get(v)||0)+1));let maxCount=0;counts.forEach(v=>{if(v>maxCount)maxCount=v;});if(maxCount<=1)return{frequency:1,modes:[],modeText:"없음",count:values.length};const modes=Array.from(counts.entries()).filter(([,c])=>c===maxCount).map(([v])=>v).sort((a,b)=>a-b);return{frequency:maxCount,modes,modeText:modes.join(", "),count:values.length}}function render(root,api){root.innerHTML=`<div class="hm-calc-panel"><div class="hm-calc-form"><div class="hm-calc-field"><label for="hm-mode-values">숫자 입력</label><textarea id="hm-mode-values" class="hm-calc-textarea" rows="4" placeholder="예: 1, 2, 2, 3, 3"></textarea><p class="hm-calc-hint">가장 자주 나타나는 값이 여러 개면 모두 표시합니다.</p></div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">최빈값 찾기</button><button type="button" class="hm-calc-btn secondary">초기화</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>`;const v=root.querySelector("textarea"),[go,reset]=root.querySelectorAll("button"),msg=root.querySelector(".hm-calc-message"),res=root.querySelector(".hm-calc-result");go.addEventListener("click",()=>{const r=compute({values:v.value});if(r.error){api.setMessage(msg,r.error);api.clearResult(res);return}api.setMessage(msg,"");const detail=r.modeText==="없음"?"모든 값의 빈도가 같습니다.":`<dl><dt>최대 빈도</dt><dd>${r.frequency}회</dd><dt>입력 개수</dt><dd>${r.count}개</dd></dl>`;api.setResult(res,api.resultCard("최빈값",api.escapeHTML(r.modeText),detail));});reset.addEventListener("click",()=>{v.value="";api.setMessage(msg,"");api.clearResult(res);v.focus();});}w.HM_CALC.register(ID,{compute,render});})(window);
